/* global Office */

/**
 * commands.js — intentionally minimal.
 *
 * The actual OnMessageSend handler lives in launchevent.js, which is what
 * the manifest's V1.1 Runtime block loads as the JavaScript override
 * (JSRuntime.Url -> launchevent.js).
 *
 * commands.js is still bundled into commands.html by webpack because
 * commands.html is referenced as FunctionFile in the manifest, but it
 * doesn't need to register any actions itself today. If we add
 * executeFunction-style ribbon buttons later (buttons that run JS
 * rather than opening the taskpane), the handler functions for those
 * would live here.
 */

Office.onReady(() => {
  // No-op. Handler registration happens in launchevent.js.
});
